  ('disabled-0489de64-moex-00024', 'disabled-0489de64', 'disabled-0489de64-moex-114-decd973b', 'sub-disabled-0489de64-02', NULL, 'single_choice', '關於有限公司董事之敘述，下列何者正確？', '["董事得經股東表決權過半數之同意，就有行為能力之股東中選任之", "不得無故辭職", "董事至少3人且不用組成董事會", "有限公司章程應記載董事姓名或名稱"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:19+00:00", "source_pdf_sha1": "0c2a462631d6", "answer_pdf_sha1": "0408f66f88b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "307", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗(作文、中華民國憲法及法學緒論)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "交通行政"}'::jsonb, NULL),
  ('disabled-0489de64-moex-00025', 'disabled-0489de64', 'disabled-0489de64-moex-114-decd973b', 'sub-disabled-0489de64-02', NULL, 'single_choice', '下列何者非家庭暴力防治法之保護對象？', '["遭受前夫精神騷擾及脅迫者", "目睹父親毆打母親之小孩", "同住之伯父恐嚇將斷其手腳", "要求交往但遭拒絕之男同學，恐嚇將殺害其全家"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:19+00:00", "source_pdf_sha1": "0c2a462631d6", "answer_pdf_sha1": "0408f66f88b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "307", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗(作文、中華民國憲法及法學緒論)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "交通行政"}'::jsonb, NULL),
  ('disabled-0489de64-moex-00026', 'disabled-0489de64', 'disabled-0489de64-moex-114-decd973b', 'sub-disabled-0489de64-02', NULL, 'single_choice', '下列何種契約是民法債編所規定之有名契約？', '["代理契約", "醫療契約", "授權契約", "出版契約"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:19+00:00", "source_pdf_sha1": "0c2a462631d6", "answer_pdf_sha1": "0408f66f88b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "307", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗(作文、中華民國憲法及法學緒論)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "交通行政"}'::jsonb, NULL),
  ('disabled-0489de64-moex-00027', 'disabled-0489de64', 'disabled-0489de64-moex-114-decd973b', 'sub-disabled-0489de64-02', NULL, 'single_choice', '有關國民參與審判制度之進行，下列敘述何者錯誤？', '["檢察官起訴時，應向管轄法院提出起訴書，並不得將卷宗及證物一併送 交法院", "起訴書不得記載使法院就案件產生預斷之虞之內容", "起訴書就犯罪事實之記載，以載明日、時、處所及方法特定之", "法院於第一次審判期日前，認為檢察官指出之證明方法顯不足認定被告 有成立犯罪之可能時，應以裁定定期通知檢察官補正"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:19+00:00", "source_pdf_sha1": "0c2a462631d6", "answer_pdf_sha1": "0408f66f88b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "307", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗(作文、中華民國憲法及法學緒論)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "交通行政"}'::jsonb, NULL),
  ('disabled-0489de64-moex-00028', 'disabled-0489de64', 'disabled-0489de64-moex-114-decd973b', 'sub-disabled-0489de64-02', NULL, 'single_choice', '甲出賣其所有之 A 地於乙，甲交付 A 地於乙，乙為 A 地所有人。下列敘 述，何者錯誤？', '["若乙脅迫甲締結A地買賣契約，甲得撤銷買賣契約", "若無約定，甲尚未移轉A地所有權於乙，乙得拒絕支付價金於甲", "若乙出賣A地於丙者，乙與丙間之A地買賣契約，效力未定", "若乙移轉A地所有權並辦理移轉登記於善意之丁，丁為A地所有人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:19+00:00", "source_pdf_sha1": "0c2a462631d6", "answer_pdf_sha1": "0408f66f88b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "307", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗(作文、中華民國憲法及法學緒論)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "交通行政"}'::jsonb, NULL),
  ('disabled-0489de64-moex-00029', 'disabled-0489de64', 'disabled-0489de64-moex-114-decd973b', 'sub-disabled-0489de64-02', NULL, 'single_choice', '甲為 22 歲之美國籍人士，來臺灣受僱於某僱用勞工 5 人以上之公司，擔 任兼職工作，依我國勞工保險條例之規定，下列敘述何者正確？', '["甲為外國籍員工，不得參加我國之勞工保險", "應由雇主為甲申報參加勞工保險", "甲為兼職員工，雇主無須為甲辦理投保", "甲無投保義務，仍得自願參加勞工保險"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:19+00:00", "source_pdf_sha1": "0c2a462631d6", "answer_pdf_sha1": "0408f66f88b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "307", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗(作文、中華民國憲法及法學緒論)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "交通行政"}'::jsonb, NULL)
